def solve(grid: List[List[int]], k: int) -> int:
    m = len(grid)
    if m == 0:
        return 0
    n = len(grid[0])
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    count = 0

    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0:
                queue = deque()
                queue.append((i, j))
                current_sum = 0
                while queue:
