from collections import deque

def solve(grid: list[list[int]], k: int) -> int:
    m = len(grid)
    n = len(grid[0]) if m > 0 else 0
    directions = [(-1, 0), (1, 0), (0, -1), (0, 1)]
    count = 0
    for i in range(m):
        for j in range(n):
            if grid[i][j] > 0:
                queue = deque()
                queue.append((i, j))
                sum_island = 0
                while queue:
                    x, y = queue.popleft()
                    sum_island += grid[x][y]
                    grid[x][y] = 0
                    for dx, dy in directions:
                        nx = x + dx
                        ny = y + dy
                        if 0 <= nx < m and 0 <= ny < n and grid[nx][ny] > 0:
                            queue.append((nx, ny))
                if sum_island % k == 0:
                    count += 1
    return count
